formulas.expression:
False 
/*   16/5/24 - changed to False hardcoded 
  OR(
    REGEX(Var_CountryCode, '^(MA|NG|DZ)$'),
    REGEX(LOWER(Var_CountryName), '^(morocco|nigeria|algeria)$')
  ) */

OR(
  CONTAINS(LOWER({!Var_Department}), "marketing: pr / comms / social media")
)

IF(
  BLANKVALUE({!Fit_Score_Department_Tier_Override},0)<>0,
    {!Fit_Score_Department_Tier_Override},
  IF(
    {!Fit_Score_Industry_Department_Tier_1} = 1,
    1,
    IF(
      OR(
        {!Fit_Score_Industry_Department_Tier_2} = 2,
        {!Fit_Score_Industry_Department_Tier_3} = 2
      ),
      2,
      {!Fit_Score_Industry_Department_Tier_4}
    )
  )
)

OR(
REGEX(LOWER({!Var_Title}), "(.* pr|pr .*|.* pr .*|sales development representative.*|account manager|accounting director|client service specialist|customer support associate|customer support manager|customer support representative|senior vice president \\(svp\\) of customer service|support specialist|vice president \\(vp\\) of customer service|account executive|account representative|b2b sales specialist|sales associate)")
)

IF(
  REGEX(LOWER({!Var_Title}), "^(student|intern)$"), "Student / Intern", /* Exact match for 'student' or 'intern' */
  IF(
    REGEX(LOWER({!Var_Title}), "^(business owner|entrepreneur|executive)$"), "Management (C-Level)", /* Exact match for these titles */
    IF(
      REGEX(LOWER({!Var_Title}), "^(web developer|software engineer|it manager|it professional|it specialist|devops engineer)$"), "R&D", /* Exact match for R&D roles */
      IF(
        REGEX(LOWER({!Var_Title}), ".*(general manager|svp).*"), "Marketing: Management / General", /* Contains 'general manager' or 'svp' */
        IF(
          AND(
            REGEX(LOWER({!Var_Title}), ".*chief.*"), 
            REGEX(LOWER({!Var_Title}), ".*officer.*")
          ), "Management (C-Level)", /* Both 'chief' and 'officer' must be present somewhere */
          IF(
            REGEX(LOWER({!Var_Title}), ".*ceo.*"), "Management (C-Level)", /* Contains 'ceo' */
            IF(
              REGEX(LOWER({!Var_Title}), ".*seo.*"), "Marketing: SEO / Content", /* Contains 'seo' */
              {!Var_Department} /* Default case for no matches */
            )
          )
        )
      )
    )
  )
)

OR(
  /*Criteria for 'Adtech and Adnetwork|B2B Software|Payments'*/
  AND(
    REGEX(LOWER({!Var_SW_Industry}), '.*(adtech and adnetwork|b2b software|payments).*'),
    REGEX(LOWER({!Var_Department}), '.*(account management / customer success|management.*(c-level)|sales / business development|sales operations).*')
  ), 
  /*Criteria for 'Agency'*/
  AND(
    LOWER({!Var_SW_Industry}) = 'agency',
    REGEX(LOWER({!Var_Department}), '.*(account management / customer success|management.*(c-level)|marketing analytics and management|marketing seo and content|marketing general|marketing: affiliate / media buying|marketing: general|marketing: ppc / display|marketing: pr / comms / social media|sales / business development|strategy / market research|marketing: management / general).*')
  ), 
  /*Criteria for 'Publishers and Media|Media and Entertainment'*/
  AND(
    REGEX(LOWER({!Var_SW_Industry}), '.*(publishers and media|media and entertainment).*'),
    REGEX(LOWER({!Var_Department}), '.*(bi / analytics|marketing seo and content|marketing: seo / content|marketing: affiliate / media buying|marketing: ppc / display|sales / business development|strategy / market research).*')
  ), 
  /*Criteria for 'CPG|Financial Services|Retail.*Ecommerce'*/
  AND(
    REGEX(LOWER({!Var_SW_Industry}), '.*(cpg|financial services|retail.*ecommerce).*'),
    REGEX(LOWER({!Var_Department}), '.*(bi / analytics|corp dev|marketing analytics and management|strategy / market research|ecommerce).*')
  ), 
  /*Criteria for 'Hedge Funds.*Asset Management|.*Private Equity.*|Venture Capital|Equity Research'*/
  AND(
    REGEX(LOWER({!Var_SW_Industry}), '.*(hedge funds.*asset management|.*private equity.*|venture capital|equity research).*'),
    REGEX(LOWER({!Var_Department}), '.*(corporate development / (m&a|mergers and acquisitions)|investment|investment banking|investors).*')
  )
)
